import{_ as p,c as a}from"./app.0b00aae6.js";const e={},t=a('<h1 id="_06-\u8BB2-\u4F60\u771F\u7684\u61C2\u6D4B\u8BD5\u8986\u76D6\u7387\u5417" tabindex="-1"><a class="header-anchor" href="#_06-\u8BB2-\u4F60\u771F\u7684\u61C2\u6D4B\u8BD5\u8986\u76D6\u7387\u5417" aria-hidden="true">#</a> 06 \u8BB2\uFF1A\u4F60\u771F\u7684\u61C2\u6D4B\u8BD5\u8986\u76D6\u7387\u5417\uFF1F</h1><p>\u5728\u4E0A\u4E00\u7BC7\u6587\u7AE0\u4E2D\uFF0C\u6211\u4E3A\u4F60\u4ECB\u7ECD\u4E86\u8F6F\u4EF6\u6D4B\u8BD5\u5404\u4E2A\u9636\u6BB5\u7684\u81EA\u52A8\u5316\u6280\u672F\uFF0C\u5728\u524D\u9762\u7684\u6587\u7AE0\u4E2D\u6211\u4E5F\u63D0\u5230\u4E86\u6D4B\u8BD5\u8986\u76D6\u7387\u7684\u6982\u5FF5\uFF0C\u4F60\u5F53\u65F6\u53EF\u80FD\u6709\u70B9\u4E0D\u660E\u767D\uFF0C\u90A3\u4E48\u4ECA\u5929\u6211\u5C31\u548C\u4F60\u8BE6\u7EC6\u804A\u804A\u6D4B\u8BD5\u8986\u76D6\u7387\u8FD9\u4E2A\u4E3B\u9898\u3002</p><p><strong>\u6D4B\u8BD5\u8986\u76D6\u7387\u901A\u5E38\u88AB\u7528\u6765\u8861\u91CF\u6D4B\u8BD5\u7684\u5145\u5206\u6027\u548C\u5B8C\u6574\u6027\uFF0C\u4ECE\u5E7F\u4E49\u7684\u89D2\u5EA6\u6765\u8BB2\uFF0C\u6D4B\u8BD5\u8986\u76D6\u7387\u4E3B\u8981\u5206\u4E3A\u4E24\u5927\u7C7B\uFF0C\u4E00\u7C7B\u662F\u9762\u5411\u9879\u76EE\u7684\u9700\u6C42\u8986\u76D6\u7387\uFF0C\u53E6\u4E00\u7C7B\u662F\u66F4\u504F\u5411\u6280\u672F\u7684\u4EE3\u7801\u8986\u76D6\u7387</strong>\u3002</p><p><strong>\u9700\u6C42\u8986\u76D6\u7387</strong></p><p><strong>\u9700\u6C42\u8986\u76D6\u7387\u662F\u6307\u6D4B\u8BD5\u5BF9\u9700\u6C42\u7684\u8986\u76D6\u7A0B\u5EA6\uFF0C\u901A\u5E38\u7684\u505A\u6CD5\u662F\u5C06\u6BCF\u4E00\u6761\u5206\u89E3\u540E\u7684\u8F6F\u4EF6\u9700\u6C42\u548C\u5BF9\u5E94\u7684\u6D4B\u8BD5\u5EFA\u7ACB\u4E00\u5BF9\u591A\u7684\u6620\u5C04\u5173\u7CFB\uFF0C\u6700\u7EC8\u76EE\u6807\u662F\u4FDD\u8BC1\u6D4B\u8BD5\u53EF\u4EE5\u8986\u76D6\u6BCF\u4E2A\u9700\u6C42\uFF0C\u4EE5\u4FDD\u8BC1\u8F6F\u4EF6\u4EA7\u54C1\u7684\u8D28\u91CF</strong>\u3002</p><p>\u6211\u4EEC\u901A\u5E38\u91C7\u7528 ALM\uFF0CDoors \u548C TestLink \u7B49\u9700\u6C42\u7BA1\u7406\u5DE5\u5177\u6765\u5EFA\u7ACB\u9700\u6C42\u548C\u6D4B\u8BD5\u7684\u5BF9\u5E94\u5173\u7CFB\uFF0C\u5E76\u4EE5\u6B64\u8BA1\u7B97\u6D4B\u8BD5\u8986\u76D6\u7387\u3002</p><p>\u9700\u6C42\u8986\u76D6\u7387\u7EDF\u8BA1\u65B9\u6CD5\u5C5E\u4E8E\u4F20\u7EDF\u7011\u5E03\u6A21\u578B\u4E0B\u7684\u8F6F\u4EF6\u5DE5\u7A0B\u5B9E\u8DF5\uFF0C\u4F20\u7EDF\u7011\u5E03\u6A21\u578B\u8FFD\u6C42\u81EA\u4E0A\u800C\u4E0B\u5730\u5236\u5B9A\u8BA1\u5212\u3001\u5206\u6790\u9700\u6C42\u3001\u8BBE\u8BA1\u8F6F\u4EF6\u3001\u7F16\u5199\u4EE3\u7801\u3001\u6D4B\u8BD5\u548C\u8FD0\u7EF4\u7B49\uFF0C\u5728\u6D41\u7A0B\u4E0A\u662F\u91CD\u91CF\u7EA7\u7684\uFF0C\u5DF2\u7ECF\u5F88\u96BE\u9002\u5E94\u5F53\u4ECA\u4E92\u8054\u7F51\u65F6\u4EE3\u4E0B\u7684\u654F\u6377\u5F00\u53D1\u5B9E\u8DF5\u3002</p><p>\u6240\u4EE5\uFF0C\u4E92\u8054\u7F51\u6D4B\u8BD5\u9879\u76EE\u4E2D\u5F88\u5C11\u76F4\u63A5\u57FA\u4E8E\u9700\u6C42\u6765\u8861\u91CF\u6D4B\u8BD5\u8986\u76D6\u7387\uFF0C\u800C\u662F\u5C06\u8F6F\u4EF6\u9700\u6C42\u8F6C\u6362\u6210\u6D4B\u8BD5\u9700\u6C42\uFF0C\u7136\u540E\u57FA\u4E8E\u6D4B\u8BD5\u9700\u6C42\u518D\u6765\u8BBE\u8BA1\u6D4B\u8BD5\u70B9\u3002</p><p>\u56E0\u6B64\uFF0C\u73B0\u5728\u4EBA\u4EEC\u53E3\u4E2D\u7684\u6D4B\u8BD5\u8986\u76D6\u7387\uFF0C\u901A\u5E38\u9ED8\u8BA4\u6307\u4EE3\u7801\u8986\u76D6\u7387\uFF0C\u800C\u4E0D\u662F\u9700\u6C42\u8986\u76D6\u7387\u3002</p><p><strong>\u4EE3\u7801\u8986\u76D6\u7387</strong></p><p><strong>\u7B80\u5355\u6765\u8BF4\uFF0C\u4EE3\u7801\u8986\u76D6\u7387\u662F\u6307\uFF0C\u81F3\u5C11\u88AB\u6267\u884C\u4E86\u4E00\u6B21\u7684\u6761\u76EE\u6570\u5360\u6574\u4E2A\u6761\u76EE\u6570\u7684\u767E\u5206\u6BD4</strong>\u3002</p><p>\u5982\u679C\u201C\u6761\u76EE\u6570\u201D\u662F\u8BED\u53E5\uFF0C\u5BF9\u5E94\u7684\u5C31\u662F\u4EE3\u7801\u884C\u8986\u76D6\u7387\uFF1B\u5982\u679C\u201C\u6761\u76EE\u6570\u201D\u662F\u51FD\u6570\uFF0C\u5BF9\u5E94\u7684\u5C31\u662F\u51FD\u6570\u8986\u76D6\u7387\uFF1B\u5982\u679C\u201C\u6761\u76EE\u6570\u201D\u662F\u8DEF\u5F84\uFF0C\u90A3\u4E48\u5BF9\u5E94\u7684\u5C31\u662F\u8DEF\u5F84\u8986\u76D6\u7387\u3002\u4F9D\u6B64\u7C7B\u63A8\uFF0C\u4F60\u5C31\u53EF\u4EE5\u5F97\u5230\u7EDD\u5927\u591A\u6570\u5E38\u89C1\u7684\u4EE3\u7801\u8986\u76D6\u7387\u7C7B\u578B\u7684\u5B9A\u4E49\u3002</p><p>\u8FD9\u91CC\u6211\u7ED9\u4F60\u7B80\u5355\u4ECB\u7ECD\u4E00\u4E0B\u6700\u5E38\u7528\u7684\u4E09\u79CD\u4EE3\u7801\u8986\u76D6\u7387\u6307\u6807\u3002</p><ul><li>\u884C\u8986\u76D6\u7387\u53C8\u79F0\u4E3A\u8BED\u53E5\u8986\u76D6\u7387\uFF0C\u6307\u5DF2\u7ECF\u88AB\u6267\u884C\u5230\u7684\u8BED\u53E5\u5360\u603B\u53EF\u6267\u884C\u8BED\u53E5\uFF08\u4E0D\u5305\u542B\u7C7B\u4F3C C++\u7684\u5934\u6587\u4EF6\u58F0\u660E\u3001\u4EE3\u7801\u6CE8\u91CA\u3001\u7A7A\u884C\u7B49\u7B49\uFF09\u7684\u767E\u5206\u6BD4\u3002\u8FD9\u662F\u6700\u5E38\u7528\u4E5F\u662F\u8981\u6C42\u6700\u4F4E\u7684\u8986\u76D6\u7387\u6307\u6807\u3002\u5B9E\u9645\u9879\u76EE\u4E2D\u901A\u5E38\u4F1A\u7ED3\u5408\u5224\u5B9A\u8986\u76D6\u7387\u6216\u8005\u6761\u4EF6\u8986\u76D6\u7387\u4E00\u8D77\u4F7F\u7528\u3002</li><li>\u5224\u5B9A\u8986\u76D6\u53C8\u79F0\u5206\u652F\u8986\u76D6\uFF0C\u7528\u4EE5\u5EA6\u91CF\u7A0B\u5E8F\u4E2D\u6BCF\u4E00\u4E2A\u5224\u5B9A\u7684\u5206\u652F\u662F\u5426\u90FD\u88AB\u6D4B\u8BD5\u5230\u4E86\uFF0C\u5373\u4EE3\u7801\u4E2D\u6BCF\u4E2A\u5224\u65AD\u7684\u53D6\u771F\u5206\u652F\u548C\u53D6\u5047\u5206\u652F\u662F\u5426\u5404\u88AB\u8986\u76D6\u81F3\u5C11\u5404\u4E00\u6B21\u3002\u6BD4\u5982\uFF0C\u5BF9\u4E8E if(a&gt;0 &amp;&amp; b&gt;0)\uFF0C\u5C31\u8981\u6C42\u8986\u76D6\u201Ca&gt;0 &amp;&amp; b&gt;0\u201D\u4E3A TRUE \u548C FALSE \u5404\u4E00\u6B21\u3002</li><li>\u6761\u4EF6\u8986\u76D6\u662F\u6307\uFF0C\u5224\u5B9A\u4E2D\u7684\u6BCF\u4E2A\u6761\u4EF6\u7684\u53EF\u80FD\u53D6\u503C\u81F3\u5C11\u6EE1\u8DB3\u4E00\u6B21\uFF0C\u5EA6\u91CF\u5224\u5B9A\u4E2D\u7684\u6BCF\u4E2A\u6761\u4EF6\u7684\u7ED3\u679C TRUE \u548C FALSE \u662F\u5426\u90FD\u88AB\u6D4B\u8BD5\u5230\u4E86\u3002\u6BD4\u5982\uFF0C\u5BF9\u4E8E if(a&gt;0 &amp;&amp; b&gt;0)\uFF0C\u5C31\u8981\u6C42\u201Ca&gt;0\u201D\u53D6 TRUE \u548C FALSE \u5404\u4E00\u6B21\uFF0C\u540C\u65F6\u8981\u6C42\u201Cb&gt;0\u201D\u53D6 TRUE \u548C FALSE \u5404\u4E00\u6B21\u3002</li></ul><p><strong>\u4EE3\u7801\u8986\u76D6\u7387\u7684\u4EF7\u503C</strong></p><p><strong>\u73B0\u5728\u5F88\u591A\u9879\u76EE\u90FD\u5728\u5355\u5143\u6D4B\u8BD5\u4EE5\u53CA\u96C6\u6210\u6D4B\u8BD5\u9636\u6BB5\u7EDF\u8BA1\u4EE3\u7801\u8986\u76D6\u7387\uFF0C\u4F46\u662F\u6211\u60F3\u8BF4\u7684\u662F\uFF0C\u7EDF\u8BA1\u4EE3\u7801\u8986\u76D6\u7387\u4EC5\u4EC5\u662F\u624B\u6BB5\uFF0C\u4F60\u5FC5\u987B\u900F\u8FC7\u73B0\u8C61\u770B\u5230\u4E8B\u7269\u7684\u672C\u8D28\uFF0C\u624D\u80FD\u4ECE\u6839\u672C\u4E0A\u4FDD\u8BC1\u8F6F\u4EF6\u6574\u4F53\u7684\u8D28\u91CF</strong>\u3002</p><p><em>\u7EDF\u8BA1\u4EE3\u7801\u8986\u76D6\u7387\u7684\u6839\u672C\u76EE\u7684\u662F\u627E\u51FA\u6F5C\u5728\u7684\u9057\u6F0F\u6D4B\u8BD5\u7528\u4F8B\uFF0C\u5E76\u6709\u9488\u5BF9\u6027\u7684\u8FDB\u884C\u8865\u5145\uFF0C\u540C\u65F6\u8FD8\u53EF\u4EE5\u8BC6\u522B\u51FA\u4EE3\u7801\u4E2D\u90A3\u4E9B\u7531\u4E8E\u9700\u6C42\u53D8\u66F4\u7B49\u539F\u56E0\u9020\u6210\u7684\u4E0D\u53EF\u8FBE\u7684\u5E9F\u5F03\u4EE3\u7801</em>\u3002</p><p>\u901A\u5E38\u6211\u4EEC\u5E0C\u671B\u4EE3\u7801\u8986\u76D6\u7387\u8D8A\u9AD8\u8D8A\u597D\uFF0C\u4EE3\u7801\u8986\u76D6\u7387\u8D8A\u9AD8\u8D8A\u80FD\u8BF4\u660E\u4F60\u7684\u6D4B\u8BD5\u7528\u4F8B\u8BBE\u8BA1\u662F\u5145\u5206\u4E14\u5B8C\u5907\u7684\uFF0C\u4F46\u4F60\u4E5F\u4F1A\u53D1\u73B0\u6D4B\u8BD5\u7684\u6210\u672C\u4F1A\u968F\u7740\u4EE3\u7801\u8986\u76D6\u7387\u7684\u63D0\u9AD8\u4EE5\u7C7B\u4F3C\u6307\u6570\u7EA7\u7684\u65B9\u5F0F\u8FC5\u901F\u589E\u52A0\u3002</p><p>\u5982\u679C\u60F3\u8FBE\u5230 70%\u7684\u4EE3\u7801\u8986\u76D6\u7387\uFF0C\u4F60\u53EF\u80FD\u53EA\u9700\u8981 30 \u5206\u949F\u7684\u65F6\u95F4\u6210\u672C\u3002\u4F46\u5982\u679C\u4F60\u60F3\u628A\u4EE3\u7801\u8986\u76D6\u7387\u63D0\u9AD8\u5230 90%\uFF0C\u90A3\u4E48\u4E3A\u4E86\u8FD9\u989D\u5916\u7684 20%\uFF0C\u4F60\u53EF\u80FD\u82B1\u7684\u65F6\u95F4\u5C31\u8FDC\u4E0D\u6B62 30 \u5206\u949F\u4E86\u3002\u66F4\u8FDB\u4E00\u6B65\uFF0C\u4F60\u5982\u679C\u60F3\u8FBE\u5230 100%\u7684\u4EE3\u7801\u8986\u76D6\u7387\uFF0C\u53EF\u60F3\u800C\u77E5\u4F60\u82B1\u8D39\u7684\u4EE3\u4EF7\u5C31\u4F1A\u66F4\u5927\u4E86\u3002</p><p>\u90A3\u4E48\uFF0C\u4E3A\u4EC0\u4E48\u4EE3\u7801\u8986\u76D6\u7387\u7684\u63D0\u9AD8\uFF0C\u9700\u8981\u4ED8\u51FA\u8D8A\u6765\u8D8A\u5927\u7684\u4EE3\u4EF7\u5462\uFF1F\u56E0\u4E3A\u5728\u540E\u671F\uFF0C\u4F60\u9700\u8981\u5927\u91CF\u7684\u6869\u4EE3\u7801\u3001Mock \u4EE3\u7801\u548C\u5168\u5C40\u53D8\u91CF\u7684\u914D\u5408\u6765\u63A7\u5236\u6267\u884C\u8DEF\u5F84\u3002</p><p>\u6240\u4EE5\uFF0C\u5728\u8F6F\u4EF6\u4F01\u4E1A\u4E2D\uFF0C\u53EA\u6709\u5355\u5143\u6D4B\u8BD5\u9636\u6BB5\u5BF9\u4EE3\u7801\u8986\u76D6\u7387\u6709\u8F83\u9AD8\u7684\u8981\u6C42\u3002\u56E0\u4E3A\u4ECE\u6280\u672F\u5B9E\u73B0\u4E0A\u8BB2\uFF0C\u5355\u5143\u6D4B\u8BD5\u53EF\u4EE5\u6700\u5927\u5316\u5730\u5229\u7528\u6253\u6869\u6280\u672F\u6765\u63D0\u9AD8\u8986\u76D6\u7387\u3002\u800C\u4F60\u5982\u679C\u60F3\u5728\u96C6\u6210\u6D4B\u8BD5\u6216\u8005\u662F GUI \u6D4B\u8BD5\u9636\u6BB5\u5C06\u4EE3\u7801\u8986\u76D6\u7387\u63D0\u9AD8\u5230\u4E00\u5B9A\u91CF\u7EA7\uFF0C\u90A3\u4F60\u6240\u8981\u4ED8\u51FA\u7684\u4EE3\u4EF7\u662F\u5DE8\u5927\u7684\uFF0C\u800C\u4E14\u5728\u5F88\u591A\u60C5\u51B5\u4E0B\u6839\u672C\u5C31\u5B9E\u73B0\u4E0D\u4E86\u3002</p><p><strong>\u4EE3\u7801\u8986\u76D6\u7387\u7684\u5C40\u9650\u6027</strong></p><p>\u6211\u5148\u6765\u95EE\u4F60\u4E00\u4E2A\u95EE\u9898\uFF0C\u5982\u679C\u4F60\u901A\u8FC7\u52AA\u529B\uFF0C\u5DF2\u7ECF\u628A\u67D0\u4E2A\u51FD\u6570\u7684 MC/DC \u4EE3\u7801\u8986\u76D6\u7387\uFF08MC/DC \u8986\u76D6\u7387\u662F\u6700\u9AD8\u6807\u51C6\u7684\u4EE3\u7801\u8986\u76D6\u7387\u6307\u6807\uFF0C\u9664\u4E86\u76F4\u63A5\u5173\u7CFB\u4EBA\u751F\u547D\u5B89\u5168\u7684\u8F6F\u4EF6\u4EE5\u5916\uFF0C\u5F88\u5C11\u4F1A\u6709\u9879\u76EE\u4F1A\u6709\u4E25\u683C\u7684 MC/DC \u8986\u76D6\u7387\u8981\u6C42\uFF09\u505A\u5230\u4E86 100%\uFF0C\u8F6F\u4EF6\u8D28\u91CF\u662F\u5426\u5C31\u771F\u7684\u9AD8\u6795\u65E0\u5FE7\u3001\u4E07\u65E0\u4E00\u5931\u4E86\u5462\uFF1F</p><p>\u5F88\u4E0D\u5E78\uFF0C\u5373\u4F7F\u4F60\u6240\u8BBE\u8BA1\u7684\u6D4B\u8BD5\u7528\u4F8B\u5DF2\u7ECF\u8FBE\u5230 100%\u7684\u4EE3\u7801\u8986\u76D6\u7387\uFF0C\u8F6F\u4EF6\u4EA7\u54C1\u7684\u8D28\u91CF\u4E5F\u505A\u4E0D\u5230\u4E07\u65E0\u4E00\u5931\u3002\u5176\u6839\u672C\u539F\u56E0\u5728\u4E8E\u4EE3\u7801\u8986\u76D6\u7387\u7684\u8BA1\u7B97\u662F\u57FA\u4E8E\u73B0\u6709\u4EE3\u7801\u7684\uFF0C\u5E76\u4E0D\u80FD\u53D1\u73B0\u90A3\u4E9B\u201C\u672A\u8003\u8651\u67D0\u4E9B\u8F93\u5165\u201D\u4EE5\u53CA\u201C\u672A\u5904\u7406\u67D0\u4E9B\u60C5\u51B5\u201D\u5F62\u6210\u7684\u7F3A\u9677\u3002</p><p>\u6211\u7ED9\u4F60\u4E3E\u4E2A\u6781\u7AEF\u7684\u4F8B\u5B50\uFF0C\u5982\u679C\u4E00\u4E2A\u88AB\u6D4B\u51FD\u6570\u91CC\u9762\u53EA\u6709\u4E00\u884C\u4EE3\u7801\uFF0C\u53EA\u8981\u8FD9\u4E2A\u51FD\u6570\u88AB\u8C03\u7528\u8FC7\u4E86\uFF0C\u90A3\u4E48\u8861\u91CF\u8FD9\u4E00\u884C\u4EE3\u7801\u8D28\u91CF\u7684\u6240\u6709\u8986\u76D6\u7387\u6307\u6807\u90FD\u4F1A\u662F 100%\uFF0C\u4F46\u662F\u8FD9\u4E2A\u51FD\u6570\u662F\u5426\u771F\u6B63\u5B9E\u73B0\u4E86\u5E94\u8BE5\u9700\u8981\u5B9E\u73B0\u7684\u529F\u80FD\u5462\uFF1F</p><p>\u663E\u7136\uFF0C\u4EE3\u7801\u8986\u76D6\u7387\u53CD\u6620\u7684\u4EC5\u4EC5\u662F\u5DF2\u6709\u4EE3\u7801\u7684\u54EA\u4E9B\u903B\u8F91\u88AB\u6267\u884C\u8FC7\u4E86\uFF0C\u54EA\u4E9B\u903B\u8F91\u8FD8\u6CA1\u6709\u88AB\u6267\u884C\u8FC7\u3002\u4EE5\u6B64\u4E3A\u4F9D\u636E\uFF0C\u4F60\u53EF\u4EE5\u8865\u5145\u6D4B\u8BD5\u7528\u4F8B\uFF0C\u53EF\u4EE5\u53BB\u6D4B\u8BD5\u90A3\u4E9B\u8FD8\u6CA1\u6709\u8986\u76D6\u5230\u7684\u6267\u884C\u8DEF\u5F84\u3002\u4F46\u4E5F\u662F\u4EC5\u6B64\u800C\u5DF2\uFF0C\u5BF9\u4E8E\u90A3\u4E9B\u538B\u6839\u8FD8\u6CA1\u6709\u4EE3\u7801\u5B9E\u73B0\u7684\u90E8\u5206\uFF0C\u57FA\u4E8E\u4EE3\u7801\u8986\u76D6\u7387\u7684\u7EDF\u8BA1\u6307\u6807\u5C31\u65E0\u80FD\u4E3A\u529B\u4E86\u3002</p><p><em>\u603B\u7ED3\u6765\u8BB2\uFF0C\u9AD8\u7684\u4EE3\u7801\u8986\u76D6\u7387\u4E0D\u4E00\u5B9A\u80FD\u4FDD\u8BC1\u8F6F\u4EF6\u7684\u8D28\u91CF\uFF0C\u4F46\u662F\u4F4E\u7684\u4EE3\u7801\u8986\u76D6\u7387\u4E00\u5B9A\u4E0D\u80FD\u80FD\u4FDD\u8BC1\u8F6F\u4EF6\u7684\u8D28\u91CF</em>\u3002</p><p>\u597D\u4E86\uFF0C\u73B0\u5728\u4F60\u5DF2\u7ECF\u4E86\u89E3\u4E86\u4EE3\u7801\u8986\u76D6\u7387\u7684\u6982\u5FF5\u3001\u4EF7\u503C\u548C\u5C40\u9650\u6027\uFF0C\u90A3\u4E48\u63A5\u4E0B\u6765\uFF0C\u6211\u5C31\u4EE5 Java \u4EE3\u7801\u8986\u76D6\u7387\u5DE5\u5177\u4E3A\u4F8B\uFF0C\u7ED9\u4F60\u89E3\u91CA\u4E00\u4E0B\u4EE3\u7801\u8986\u76D6\u7387\u5DE5\u5177\u7684\u5185\u90E8\u5B9E\u73B0\u539F\u7406\u4EE5\u53CA\u4E00\u4E9B\u5173\u952E\u6280\u672F\u3002</p><p>\u5F53\u4F60\u7406\u89E3\u4E86\u8FD9\u90E8\u5206\u5185\u5BB9\uFF0C\u4EE5\u540E\u518D\u9762\u5BF9\u5404\u4E2A\u4E0D\u540C\u5F00\u53D1\u8BED\u8A00\u7684\u4E0D\u540C\u4EE3\u7801\u8986\u76D6\u7387\u5DE5\u5177\u65F6\uFF0C\u5C31\u53EF\u4EE5\u505A\u5230\u80F8\u6709\u6210\u7AF9\u5730\u6839\u636E\u5177\u4F53\u7684\u9879\u76EE\u6027\u8D28\uFF0C\u9009\u62E9\u6700\u5408\u9002\u7684\u4EE3\u7801\u8986\u76D6\u7387\u5DE5\u5177\u4E86\u3002</p><p><strong>\u4EE3\u7801\u8986\u76D6\u7387\u5DE5\u5177</strong></p><p>JaCoCo \u662F\u4E00\u6B3E Java \u4EE3\u7801\u7684\u4E3B\u6D41\u5F00\u6E90\u8986\u76D6\u7387\u5DE5\u5177\uFF0C\u53EF\u4EE5\u5F88\u65B9\u4FBF\u5730\u5D4C\u5165\u5230 Ant\u3001Maven \u4E2D\uFF0C\u5E76\u4E14\u548C\u5F88\u591A\u4E3B\u6D41\u7684\u6301\u7EED\u96C6\u6210\u5DE5\u5177\u4EE5\u53CA\u4EE3\u7801\u9759\u6001\u68C0\u67E5\u5DE5\u5177\uFF0C\u6BD4\u5982 Jekins \u548C Sonar \u7B49\uFF0C\u90FD\u6709\u5F88\u597D\u7684\u96C6\u6210\u3002</p><p>\u9996\u5148\uFF0C\u6211\u5148\u5E26\u4F60\u770B\u770B JaCoCo \u7684\u4EE3\u7801\u8986\u76D6\u7387\u62A5\u544A\u957F\u4EC0\u4E48\u6837\u5B50\u3002</p><p>\u5982\u56FE 1 \u6240\u793A\u4E3A JaCoCo \u7684\u6574\u4F53\u4EE3\u7801\u8986\u76D6\u7387\u7EDF\u8BA1\u62A5\u544A\uFF0C\u5305\u62EC\u4E86\u6BCF\u4E2A Java \u4EE3\u7801\u6587\u4EF6\u7684\u884C\u8986\u76D6\u7387\u4EE5\u53CA\u5206\u652F\u8986\u76D6\u7387\u7EDF\u8BA1\uFF0C\u5E76\u7ED9\u51FA\u4E86\u6BCF\u4E2A Java \u4EE3\u7801\u6587\u4EF6\u7684\u884C\u6570\u3001\u65B9\u6CD5\u6570\u548C\u7C7B\u6570\u7B49\u5177\u4F53\u4FE1\u606F\u3002 <img src="https://static001.geekbang.org/resource/image/bf/6c/bfc0cf6bed338bc8bafc008b7fa1db6c.png" alt="JaCoCo\u4EE3\u7801\u8986\u76D6\u7387\u7EDF\u8BA1\u62A5\u544A\u5B9E\u4F8B"></p><p>\u5982\u56FE 2 \u6240\u793A\u4E3A\u6BCF\u4E2A Java \u6587\u4EF6\u5185\u90E8\u8BE6\u7EC6\u7684\u4EE3\u7801\u8986\u76D6\u7387\u60C5\u51B5\uFF0C\u56FE\u4E2D\u7EFF\u8272\u7684\u884C\u8868\u793A\u5DF2\u7ECF\u88AB\u8986\u76D6\uFF0C\u7EA2\u8272\u7684\u884C\u8868\u793A\u5C1A\u672A\u88AB\u8986\u76D6\uFF0C\u9EC4\u8272\u7684\u884C\u8868\u793A\u90E8\u5206\u8986\u76D6\uFF1B\u5DE6\u4FA7\u7EFF\u8272\u83F1\u5F62\u5757\u8868\u793A\u8BE5\u5206\u652F\u5DF2\u7ECF\u88AB\u5B8C\u5168\u8986\u76D6\u3001\u9EC4\u8272\u83F1\u5F62\u5757\u8868\u793A\u8BE5\u5206\u652F\u4EC5\u88AB\u90E8\u5206\u8986\u76D6\u3002 <img src="https://static001.geekbang.org/resource/image/6b/ce/6bf54542c3acb5f8e0d3bdf62ee9e7ce.png" alt="JaCoCo\u8BE6\u7EC6\u4EE3\u7801\u8986\u76D6\u7387\u5B9E\u4F8B"></p><p>\u663E\u7136\uFF0C\u901A\u8FC7\u8FD9\u4E2A\u8BE6\u5C3D\u7684\u62A5\u544A\uFF0C\u4F60\u5C31\u53EF\u4EE5\u77E5\u9053\u4EE3\u7801\u771F\u5B9E\u7684\u6267\u884C\u60C5\u51B5\u3001\u54EA\u4E9B\u4EE3\u7801\u672A\u88AB\u8986\u76D6\u3002\u4EE5\u6B64\u4E3A\u57FA\u7840\uFF0C\u4F60\u518D\u53BB\u8BBE\u8BA1\u6D4B\u8BD5\u7528\u4F8B\u5C31\u4F1A\u66F4\u6709\u9488\u5BF9\u6027\u4E86\u3002</p><p><strong>\u4EE3\u7801\u8986\u76D6\u7387\u5DE5\u5177\u7684\u5B9E\u73B0\u539F\u7406</strong></p><p>JaCoCo \u7684\u8BE6\u7EC6\u62A5\u544A\uFF0C\u8BA9\u4F60\u60CA\u53F9\u4E8E\u4EE3\u7801\u8986\u76D6\u7387\u5DE5\u5177\u7684\u5F3A\u5927\u3002\u4F46\u4F60\u6709\u6CA1\u6709\u4ED4\u7EC6\u60F3\u8FC7\uFF0C\u8FD9\u6837\u7684\u7EDF\u8BA1\u4FE1\u606F\u5982\u4F55\u88AB\u83B7\u53D6\u5230\u7684\u5462\uFF1F <img src="https://static001.geekbang.org/resource/image/0b/d5/0b8f26275681d8d5edde60487d70e8d5.png" alt="\u7EDF\u8BA1\u4EE3\u7801\u8986\u76D6\u7387\u7684\u4E0D\u540C\u6CE8\u5165\u5B9E\u73B0\u6280\u672F"></p><p><strong>\u5B9E\u73B0\u4EE3\u7801\u8986\u76D6\u7387\u7684\u7EDF\u8BA1\uFF0C\u6700\u57FA\u672C\u7684\u65B9\u6CD5\u5C31\u662F\u6CE8\u5165\uFF08Instrumentation\uFF09\u3002\u7B80\u5355\u5730\u8BF4\uFF0C\u6CE8\u5165\u5C31\u662F\u5728\u88AB\u6D4B\u4EE3\u7801\u4E2D\u81EA\u52A8\u63D2\u5165\u7528\u4E8E\u8986\u76D6\u7387\u7EDF\u8BA1\u7684\u63A2\u9488\uFF08Probe\uFF09\u4EE3\u7801\uFF0C\u5E76\u4FDD\u8BC1\u63D2\u5165\u7684\u63A2\u9488\u4EE3\u7801\u4E0D\u4F1A\u7ED9\u539F\u4EE3\u7801\u5E26\u6765\u4EFB\u4F55\u5F71\u54CD\u3002</strong></p><p>\u5BF9\u4E8E Java \u4EE3\u7801\u6765\u8BB2\uFF0C\u6839\u636E\u6CE8\u5165\u76EE\u6807\u7684\u4E0D\u540C\uFF0C\u53EF\u4EE5\u5206\u4E3A\u6E90\u4EE3\u7801\uFF08Source Code\uFF09\u6CE8\u5165\u548C\u5B57\u8282\u7801\uFF08Byte Code\uFF09\u6CE8\u5165\u4E24\u5927\u7C7B\u3002\u57FA\u4E8E JVM \u672C\u8EAB\u7279\u6027\u4EE5\u53CA\u6267\u884C\u6548\u7387\u7684\u539F\u56E0\uFF0C\u76EE\u524D\u4E3B\u6D41\u7684\u5DE5\u5177\u57FA\u672C\u90FD\u662F\u4F7F\u7528\u5B57\u8282\u7801\u6CE8\u5165\uFF0C\u6CE8\u5165\u7684\u5177\u4F53\u5B9E\u73B0\u91C7\u7528 ASM \u6280\u672F\u3002</p><p>ASM \u662F\u4E00\u4E2A Java \u5B57\u8282\u7801\u64CD\u7EB5\u6846\u67B6\uFF0C\u80FD\u88AB\u7528\u6765\u52A8\u6001\u751F\u6210\u7C7B\u6216\u8005\u589E\u5F3A\u65E2\u6709\u7C7B\u7684\u529F\u80FD\uFF0C\u53EF\u4EE5\u76F4\u63A5\u4EA7\u751F class \u6587\u4EF6\uFF0C\u4E5F\u53EF\u4EE5\u5728\u7C7B\u88AB\u52A0\u8F7D\u5165 JVM \u4E4B\u524D\u52A8\u6001\u6539\u53D8\u7C7B\u884C\u4E3A\u3002</p><p>\u6839\u636E\u6CE8\u5165\u53D1\u751F\u7684\u65F6\u95F4\u70B9\uFF0C\u5B57\u8282\u7801\u6CE8\u5165\u53C8\u53EF\u4EE5\u5206\u4E3A\u4E24\u5927\u6A21\u5F0F\uFF1AOn-The-Fly \u6CE8\u5165\u6A21\u5F0F\u548C Offline \u6CE8\u5165\u6A21\u5F0F\u3002</p><p><strong>\u7B2C\u4E00\uFF0COn-The-Fly \u6CE8\u5165\u6A21\u5F0F</strong></p><p>On-The-Fly \u6A21\u5F0F\u7684\u7279\u70B9\u5728\u4E8E\u65E0\u9700\u4FEE\u6539\u6E90\u4EE3\u7801\uFF0C\u4E5F\u65E0\u9700\u63D0\u524D\u8FDB\u884C\u5B57\u8282\u7801\u63D2\u6869\u3002\u5B83\u9002\u7528\u4E8E\u652F\u6301 Java Agent \u7684\u8FD0\u884C\u73AF\u5883\u3002</p><p>\u8FD9\u6837\u505A\u7684\u4F18\u70B9\u662F\uFF0C\u53EF\u4EE5\u5728\u7CFB\u7EDF\u4E0D\u505C\u673A\u7684\u60C5\u51B5\u4E0B\uFF0C\u5B9E\u65F6\u6536\u96C6\u4EE3\u7801\u8986\u76D6\u7387\u4FE1\u606F\u3002\u7F3A\u70B9\u662F\u8FD0\u884C\u73AF\u5883\u5FC5\u987B\u5141\u8BB8\u4F7F\u7528 Java Agent\u3002</p><p>\u5B9E\u73B0 On-The-Fly \u6A21\u5F0F\uFF0C\u4E3B\u8981\u6709\u4E24\u79CD\u6280\u672F\u65B9\u6848\uFF1A</p><ol><li><p>\u5F00\u53D1\u81EA\u5B9A\u4E49\u7684\u7C7B\u88C5\u8F7D\u5668\uFF08Class Loader\uFF09\u5B9E\u73B0\u7C7B\u88C5\u8F7D\u7B56\u7565\uFF0C\u6BCF\u6B21\u7C7B\u52A0\u8F7D\u524D\uFF0C\u9700\u8981\u5728 class \u6587\u4EF6\u4E2D\u63D2\u5165\u63A2\u9488\uFF0C\u65E9\u671F\u7684 Emma \u5C31\u662F\u4F7F\u7528\u8FD9\u79CD\u65B9\u6848\u5B9E\u73B0\u7684\u63A2\u9488\u63D2\u5165\uFF1B</p></li><li><p>\u501F\u52A9 Java Agent\uFF0C\u5229\u7528\u6267\u884C\u5728 main()\u65B9\u6CD5\u4E4B\u524D\u7684\u62E6\u622A\u5668\u65B9\u6CD5 premain()\u6765\u63D2\u5165\u63A2\u9488\uFF0C\u5B9E\u9645\u4F7F\u7528\u8FC7\u7A0B\u4E2D\u9700\u8981\u5728 JVM \u7684\u542F\u52A8\u53C2\u6570\u4E2D\u6DFB\u52A0\u201C-javaagent\u201D\u5E76\u6307\u5B9A\u7528\u4E8E\u5B9E\u65F6\u5B57\u8282\u7801\u6CE8\u5165\u7684\u4EE3\u7406\u7A0B\u5E8F\uFF0C\u8FD9\u6837\u4EE3\u7406\u7A0B\u5E8F\u5728\u88C5\u8F7D\u6BCF\u4E2A class \u6587\u4EF6\u524D\uFF0C\u5148\u5224\u65AD\u662F\u5426\u5DF2\u7ECF\u63D2\u5165\u4E86\u63A2\u9488\uFF0C\u5982\u679C\u6CA1\u6709\u5219\u9700\u8981\u5C06\u63A2\u9488\u63D2\u5165 class \u6587\u4EF6\u4E2D\uFF0C\u76EE\u524D\u4E3B\u6D41\u7684 JaCoCo \u5C31\u662F\u4F7F\u7528\u4E86\u8FD9\u4E2A\u65B9\u5F0F\u3002</p></li></ol><p><strong>\u7B2C\u4E8C\uFF0COffline \u6CE8\u5165\u6A21\u5F0F</strong></p><p>Offline \u6A21\u5F0F\u4E5F\u65E0\u9700\u4FEE\u6539\u6E90\u4EE3\u7801\uFF0C\u4F46\u662F\u9700\u8981\u5728\u6D4B\u8BD5\u5F00\u59CB\u4E4B\u524D\u5148\u5BF9\u6587\u4EF6\u8FDB\u884C\u63D2\u6869\uFF0C\u5E76\u4E8B\u5148\u751F\u6210\u63D2\u8FC7\u6869\u7684 class \u6587\u4EF6\u3002\u5B83\u9002\u7528\u4E8E\u4E0D\u652F\u6301 Java Agent \u7684\u8FD0\u884C\u73AF\u5883\uFF0C\u4EE5\u53CA\u65E0\u6CD5\u4F7F\u7528\u81EA\u5B9A\u4E49\u7C7B\u88C5\u8F7D\u5668\u7684\u573A\u666F\u3002</p><p>\u8FD9\u6837\u505A\u7684\u4F18\u70B9\u662F\uFF0CJVM \u542F\u52A8\u65F6\u4E0D\u518D\u9700\u8981\u4F7F\u7528 Java Agent \u989D\u5916\u5F00\u542F\u4EE3\u7406\uFF0C\u7F3A\u70B9\u662F\u65E0\u6CD5\u5B9E\u65F6\u83B7\u53D6\u4EE3\u7801\u8986\u76D6\u7387\u4FE1\u606F\uFF0C\u53EA\u80FD\u5728\u7CFB\u7EDF\u505C\u673A\u65F6\u4E0B\u83B7\u53D6\u3002</p><p>Offline \u6A21\u5F0F\u6839\u636E\u662F\u751F\u6210\u65B0\u7684 class \u6587\u4EF6\u8FD8\u662F\u76F4\u63A5\u4FEE\u6539\u539F class \u6587\u4EF6\uFF0C\u53C8\u53EF\u4EE5\u5206\u4E3A Replace \u548C Inject \u4E24\u79CD\u4E0D\u540C\u6A21\u5F0F\u3002</p><p>\u548C On-The-Fly \u6CE8\u5165\u6A21\u5F0F\u4E0D\u540C\uFF0CReplace \u548C Inject \u7684\u5B9E\u73B0\u662F\uFF0C\u5728\u6D4B\u8BD5\u8FD0\u884C\u524D\u5C31\u5DF2\u7ECF\u901A\u8FC7 ASM \u5C06\u63A2\u9488\u63D2\u5165\u4E86 class \u6587\u4EF6\uFF0C\u800C\u5728\u6D4B\u8BD5\u7684\u8FD0\u884C\u8FC7\u7A0B\u4E2D\u4E0D\u9700\u8981\u4EFB\u4F55\u989D\u5916\u7684\u5904\u7406\u3002Cobertura \u5C31\u662F\u4F7F\u7528 Offline \u6A21\u5F0F\u7684\u5178\u578B\u4EE3\u8868\u3002</p><p><strong>\u603B\u7ED3</strong></p><p>\u6D4B\u8BD5\u8986\u76D6\u7387\u901A\u5E38\u88AB\u7528\u6765\u8861\u91CF\u6D4B\u8BD5\u7684\u5145\u5206\u6027\u548C\u5B8C\u6574\u6027\uFF0C\u5305\u62EC\u9762\u5411\u9879\u76EE\u7684\u9700\u6C42\u8986\u76D6\u7387\u548C\u66F4\u504F\u5411\u6280\u672F\u7684\u4EE3\u7801\u8986\u76D6\u7387\u3002\u800C\u9700\u6C42\u8986\u76D6\u7387\u7684\u7EDF\u8BA1\u65B9\u5F0F\u4E0D\u518D\u9002\u7528\u4E8E\u73B0\u5728\u7684\u654F\u6377\u5F00\u53D1\u6A21\u5F0F\uFF0C\u6240\u4EE5\u73B0\u5728\u8C08\u5230\u6D4B\u8BD5\u8986\u76D6\u7387\uFF0C\u5927\u591A\u662F\u6307\u4EE3\u7801\u8986\u76D6\u7387\u3002</p><p>\u4F46\u662F\uFF0C\u9AD8\u7684\u4EE3\u7801\u8986\u76D6\u7387\u4E0D\u4E00\u5B9A\u80FD\u4FDD\u8BC1\u8F6F\u4EF6\u7684\u8D28\u91CF\uFF0C\u56E0\u4E3A\u4EE3\u7801\u8986\u76D6\u7387\u662F\u57FA\u4E8E\u73B0\u6709\u4EE3\u7801\uFF0C\u65E0\u6CD5\u53D1\u73B0\u90A3\u4E9B\u201C\u672A\u8003\u8651\u67D0\u4E9B\u8F93\u5165\u201D\u4EE5\u53CA\u201C\u672A\u5904\u7406\u67D0\u4E9B\u60C5\u51B5\u201D\u5F62\u6210\u7684\u7F3A\u9677\u3002</p><p>\u53E6\u5916\uFF0C\u5BF9\u4E8E\u4EE3\u7801\u8986\u76D6\u7387\u7684\u7EDF\u8BA1\u5DE5\u5177\uFF0C\u6211\u5E0C\u671B\u4F60\u4E0D\u4EC5\u4EC5\u662F\u4F1A\u7528\u7684\u5C42\u6B21\uFF0C\u800C\u662F\u80FD\u591F\u7406\u89E3\u5B83\u4EEC\u7684\u539F\u7406\uFF0C\u77E5\u5176\u7136\u77E5\u5176\u6240\u4EE5\u7136\uFF0C\u624D\u80FD\u66F4\u597D\u5730\u5229\u7528\u8FD9\u4E9B\u5DE5\u5177\u5B8C\u6210\u4F60\u7684\u6D4B\u8BD5\u5DE5\u4F5C\u3002</p><p><strong>\u601D\u8003\u9898</strong></p><p>\u4F60\u5728\u5B9E\u9645\u5DE5\u4F5C\u4E2D\uFF0C\u662F\u5426\u8FD8\u63A5\u89E6\u8FC7 C/C++\uFF0CJavaScript \u7B49\u8BED\u8A00\u7684\u4EE3\u7801\u8986\u76D6\u7387\u5DE5\u5177\uFF0C\u6BD4\u5982 GCC Coverage\u3001JSCoverage \u548C Istanbul \u7B49\uFF1F\u5982\u679C\u63A5\u89E6\u8FC7\u7684\u8BDD\uFF0C\u8BF7\u4F60\u8C08\u8C08\u81EA\u5DF1\u4F7F\u7528\u7684\u611F\u53D7\u4EE5\u53CA\u9047\u5230\u8FC7\u7684\u201C\u5751\u201D\u3002</p>',57);function n(s,o){return t}var g=p(e,[["render",n],["__file","06.html.vue"]]);export{g as default};
